package ru.memearena.session.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="user_session") public class UserSession { @Id private UUID id; @Column(name="user_id",nullable=false) private UUID userId; @Column(name="token_hash",nullable=false,unique=true,length=64) private String tokenHash; @Column(name="created_at",nullable=false) private Instant createdAt; @Column(name="expires_at",nullable=false) private Instant expiresAt; @Column(name="last_used_at") private Instant lastUsedAt; @Column(name="revoked_at") private Instant revokedAt; @Column(name="installation_id",length=100) private String installationId; protected UserSession(){} public UserSession(UUID id,UUID userId,String tokenHash,Instant createdAt,Instant expiresAt,String installationId,String ipHash){this.id=id;this.userId=userId;this.tokenHash=tokenHash;this.createdAt=createdAt;this.expiresAt=expiresAt;this.installationId=installationId;} public UUID getId(){return id;} public UUID getUserId(){return userId;} public String getTokenHash(){return tokenHash;} public String getInstallationId(){return installationId;} public Instant getExpiresAt(){return expiresAt;} public Instant getRevokedAt(){return revokedAt;} public boolean expired(Instant now){return !expiresAt.isAfter(now);} public boolean revoked(){return revokedAt!=null;} public void touch(Instant now){lastUsedAt=now;} public void revoke(Instant now){if(revokedAt==null) revokedAt=now;} }
